/**
 * n8n Code node: Parse a single-post JSON object from LLM output.
 *
 * Enhancements:
 * - Extracts and normalizes `isCarasoul` and `noMedia`
 * - Accepts common alternates: isCarousel / is_carousel, no_media / media_count / num_media
 * - Converts booleans/numbers to strings; enforces light consistency:
 *    • if isCarasoul === "True" => isVideo = "False" and noMedia >= "2" (default "3" if unclear)
 *    • if isVideo === "True"   => noMedia = "1"
 *    • TikTok/YouTube: isCarasoul = "False", noMedia = "1" (platforms without image carousels)
 */

const REQUIRED_KEYS = [
  "Date",
  "Time",
  "Platform",
  "Hook",
  "Body",
  "CTA",
  "Image/Video Prompt (with size)",
  "Aspect Ratio",
  "Duration (sec)",
  "Alt Text",
  "Hashtags",
  // Existing optional schema field you had:
  "Notes",
  // Newly enforced media fields:
  "isVideo",
  "isCarasoul",
  "noMedia",
];

function firstDefined(...vals) {
  for (const v of vals) if (v !== undefined && v !== null) return v;
  return undefined;
}

function collectCandidateTexts(obj) {
  const texts = [];

  // Common fields
  if (typeof obj?.text === "string") texts.push(obj.text);
  if (typeof obj?.output === "string") texts.push(obj.output);

  // Gemini-style structure
  const candidates = obj?.candidates;
  if (Array.isArray(candidates)) {
    for (const c of candidates) {
      const parts = c?.content?.parts;
      if (Array.isArray(parts)) {
        for (const p of parts) {
          if (typeof p?.text === "string") texts.push(p.text);
        }
      }
      if (typeof c?.text === "string") texts.push(c.text);
    }
  }

  // OpenAI-style structure
  const content = obj?.content;
  if (Array.isArray(content)) {
    for (const part of content) {
      if (typeof part?.text === "string") texts.push(part.text);
    }
  }

  return texts.filter((t) => typeof t === "string" && t.trim().length > 0);
}

function stripCodeFences(s) {
  const fenceRe = /```(?:json)?\s*([\s\S]*?)```/gi;
  let match;
  let best = "";
  while ((match = fenceRe.exec(s)) !== null) {
    const candidate = match[1].trim();
    if (candidate.length > best.length) best = candidate;
  }
  if (best) return best;

  const firstBrace = s.indexOf("{");
  const lastBrace = s.lastIndexOf("}");
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    return s.slice(firstBrace, lastBrace + 1).trim();
  }
  return s.trim();
}

function cleanForJson(s) {
  let out = s.replace(/\r\n/g, "\n");
  out = out.replace(/[\u200B-\u200D\uFEFF]/g, "");

  // Try to unescape if double-encoded
  if (
    (/^["']/.test(out) && /\\["']?\{/.test(out)) ||
    (out.includes('\\"Date\\"') && out.includes('\\"Time\\"'))
  ) {
    try {
      const unescaped = JSON.parse(out);
      if (typeof unescaped === "string") {
        out = unescaped;
      }
    } catch (_) {}
  }
  return out.trim();
}

function tryParseJson(s) {
  try {
    return JSON.parse(s);
  } catch (_) {}

  const noTrailingCommas = s.replace(/,\s*([}\]])/g, "$1");
  if (noTrailingCommas !== s) {
    try {
      return JSON.parse(noTrailingCommas);
    } catch (_) {}
  }
  throw new Error("Payload is not valid JSON after cleaning");
}

function toStringValue(v) {
  if (v === undefined || v === null) return "";
  if (typeof v === "boolean") return v ? "True" : "False";
  if (typeof v === "number") return String(v);
  if (Array.isArray(v)) return v.join(" ");
  if (typeof v === "object") return JSON.stringify(v);
  return String(v);
}

function normalizeTime(t) {
  if (!t) return "";
  const s = t.trim();

  if (/^(?:[01]\d|2[0-3]):[0-5]\d$/.test(s)) return s;

  const m = s.match(/^(\d{1,2}):?([0-5]\d)?\s*([AaPp][Mm])$/);
  if (m) {
    let hh = parseInt(m[1], 10);
    const mm = m[2] ? parseInt(m[2], 10) : 0;
    const ampm = m[3].toUpperCase();
    if (ampm === "PM" && hh !== 12) hh += 12;
    if (ampm === "AM" && hh === 12) hh = 0;
    return `${String(hh).padStart(2, "0")}:${String(mm).padStart(2, "0")}`;
  }

  const m2 = s.match(/^(\d{1,2}):([0-5]\d)\s*([AaPp][Mm])$/);
  if (m2) {
    let hh = parseInt(m2[1], 10);
    const mm = parseInt(m2[2], 10);
    const ampm = m2[3].toUpperCase();
    if (ampm === "PM" && hh !== 12) hh += 12;
    if (ampm === "AM" && hh === 12) hh = 0;
    return `${String(hh).padStart(2, "0")}:${String(mm).padStart(2, "0")}`;
  }
  return s;
}

function normalizeHashtags(s) {
  if (!s) return "";
  const tokens = s
    .replace(/\s+/g, " ")
    .trim()
    .split(" ")
    .filter((tok) => /^#\w[\w-]*$/.test(tok));
  return tokens.join(" ");
}

function parseBooleanish(v) {
  if (v === undefined || v === null) return undefined;
  if (typeof v === "boolean") return v;
  if (typeof v === "number") return v !== 0;
  const s = String(v).trim().toLowerCase();
  if (["true", "yes", "y", "1"].includes(s)) return true;
  if (["false", "no", "n", "0"].includes(s)) return false;
  return undefined;
}

function parseIntegerish(v) {
  if (v === undefined || v === null) return undefined;
  if (typeof v === "number" && Number.isFinite(v)) return Math.round(v);
  const s = String(v).trim();
  const n = parseInt(s, 10);
  if (!Number.isNaN(n)) return n;
  return undefined;
}

function ensureSchema(obj) {
  const out = {};

  for (const key of REQUIRED_KEYS) {
    let val = obj[key];

    if (val === undefined) {
      switch (key) {
        case "Date":
          val = firstDefined(obj.date, obj.start_date);
          break;
