  out["Hashtags"] = normalizeHashtags(out["Hashtags"]);

  // Media logic harmonization
  const platform = (out["Platform"] || "").trim().toLowerCase();

  // Parse booleans/ints from possibly string values
  let isVideo = parseBooleanish(out["isVideo"]);
  let isCar = parseBooleanish(out["isCarasoul"]);
  let noMedia = parseIntegerish(out["noMedia"]);

  // Platform constraints (TikTok/YouTube: no image carousels)
  const platformNoCarousel =
    platform === "tiktok" || platform === "youtube" || platform === "youtube shorts" || platform === "shorts";

  if (platformNoCarousel) {
    isCar = false;
    // If isVideo not explicitly false, assume video
    if (isVideo === undefined) isVideo = true;
    noMedia = 1;
  }

  // If carousel => force image carousel semantics
  if (isCar === true) {
    isVideo = false;
    if (noMedia === undefined || noMedia < 2) noMedia = 3; // sensible default
  }

  // If video => exactly one media unit
  if (isVideo === true) {
    noMedia = 1;
  }

  // If neither provided, default to 1 media unit
  if (isVideo === undefined && isCar === undefined && (noMedia === undefined || noMedia < 1)) {
    noMedia = 1;
  }

  // Write back normalized strings
  if (isVideo !== undefined) out["isVideo"] = toStringValue(isVideo);
  else out["isVideo"] = out["isVideo"] || "";

  if (isCar !== undefined) out["isCarasoul"] = toStringValue(isCar);
  else out["isCarasoul"] = out["isCarasoul"] || "";

  if (noMedia !== undefined) out["noMedia"] = toStringValue(noMedia);
  else out["noMedia"] = out["noMedia"] || "";

  return out;
}

