// n8n Function node
// Input: items[].json.output (string containing the full calendar text with a Markdown table)
// Output: one item per row with EXACT keys in this order (no extras).

function getOutputTextArray(items) {
  const texts = [];
  for (const it of items) {
    const j = it.json ?? it;
    if (typeof j.output === 'string' && j.output.trim()) texts.push(j.output);
    // Fallbacks (if your field is in a different place)
    else if (typeof j.text === 'string' && j.text.trim()) texts.push(j.text);
    else if (typeof it.output === 'string' && it.output.trim()) texts.push(it.output);
  }
  return texts;
}

function findTableLines(text) {
  const lines = text.split(/\r?\n/);

  // Header must match EXACT column names
  const headerRe = /^\s*\|\s*Date\s*\|\s*Time\s*\|\s*Platform\s*\|\s*Pillar\s*\|\s*Topic\s*\|\s*Posting Idea \(Strategy Only\)\s*\|\s*Hashtags\s*\|\s*$/i;

  let headerIdx = -1;
  for (let i = 0; i < lines.length; i++) {
    if (headerRe.test(lines[i])) {
      headerIdx = i;
      break;
    }
  }
  if (headerIdx === -1) return [];

  // Expect a separator (---) line next, but be tolerant
  let start = headerIdx + 1;
  if (lines[start] && /^\s*\|?\s*-{3,}/.test(lines[start])) start++;

  // Collect table body until a non-row line
  const body = [];
  for (let i = start; i < lines.length; i++) {
    const line = lines[i];
    // Stop at next section or blank
    if (!line.trim()) break;
    if (/^\s*-{3,}\s*$/.test(line)) break; // a '---' divider
    if (/^\s*[A-Z]\)\s/.test(line)) break; // "B) Fallback..." etc.
    if (!/^\s*\|.*\|\s*$/.test(line)) break; // not a pipe row
    body.push(line);
  }
  return body;
}

function splitRowIntoCells(line) {
  // Split on '|' and trim; remove leading/trailing empties due to boundary pipes
  let parts = line.split('|').map(s => s.trim());
  if (parts.length && parts[0] === '') parts.shift();
  if (parts.length && parts[parts.length - 1] === '') parts.pop();
  return parts;
}

function normalizeCell(s) {
  return s
    .replace(/\s+/g, ' ')   // collapse whitespace
    .replace(/\s*\|\s*/g, ' | ') // (rare) keep any literal pipes readable
    .trim();
}

const REQUIRED = [
  'Date',
  'Time',
  'Platform',
  'Pillar',
  'Topic',
  'Posting Idea (Strategy Only)',
  'Hashtags',
];

const texts = getOutputTextArray(items);
const out = [];

for (const text of texts) {
  const rows = findTableLines(text);

  for (const row of rows) {
    const cells = splitRowIntoCells(row).map(normalizeCell);

    // Expect at least 7 cells; if more, merge overflow into the last (hashtags) to avoid losing data.
    let cols;
    if (cells.length >= 7) {
      cols = [
        cells[0], // Date
        cells[1], // Time
        cells[2], // Platform
        cells[3], // Pillar
        cells[4], // Topic
        cells[5], // Posting Idea (Strategy Only)
        cells.slice(6).join(' ') // Hashtags (+ any overflow merged)
      ];
    } else {
