parameters.jsCode:
/**
 * n8n Function node
 * Input can be:
 * [
 *   { json: { top5competitors: [ { name, website, domain, socials:{...}, links?:[], pages?:[], other_links?:[] } ] } }
 * ]
 *
 * Output:
 * [
 *   {
 *     json: {
 *       by_platform: { facebook:[], instagram:[], linkedin:[], tiktok:[], youtube:[], x:[], pinterest:[], whatsapp:[], other:[] },
 *       all: [...],
 *       counts: { ... },
 *       _debug: { items_in, records_scanned, used: { by_platform, all, links } }
 *     }
 *   }
 * ]
 */

const PLATFORMS = ["facebook","instagram","linkedin","tiktok","youtube","x","pinterest","whatsapp","other"];

// ---------- helpers ----------
function uniqCI(arr) {
  const seen = new Set();
  const out = [];
  for (const v of (arr || [])) {
    const s = String(v || "").trim();
    if (!s) continue;
    const key = s.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(s);
  }
  return out;
}

function normUrl(u) {
  if (!u) return null;
  let s = String(u).trim();
  if (!s) return null;
  // add scheme if missing
  if (!/^https?:\/\//i.test(s)) s = `https://${s.replace(/^\/+/, "")}`;
  // normalize twitter -> x
  s = s.replace(/twitter\.com/ig, "x.com");
  // normalize accidental spaces
  s = s.replace(/\s+/g, "");
  return s;
}

function pushUrl(bucket, url) {
  const u = normUrl(url);
  if (u) bucket.push(u);
}

function detectPlatform(url) {
  const u = (url || "").toLowerCase();
  if (u.includes("facebook.com") || u.includes("fb.com")) return "facebook";
  if (u.includes("instagram.com")) return "instagram";
  if (u.includes("linkedin.com")) return "linkedin";
  if (u.includes("tiktok.com")) return "tiktok";
  if (u.includes("youtube.com") || u.includes("youtu.be")) return "youtube";
  if (u.includes("x.com")) return "x";
  if (u.includes("pinterest.com")) return "pinterest";
  if (u.includes("wa.me") || u.includes("whatsapp.com")) return "whatsapp";
  return "other";
}

// ---------- collect input competitors ----------
let competitors = [];
for (const it of items) {
  const j = it.json || {};
  if (Array.isArray(j.top5competitors)) {
    competitors = competitors.concat(j.top5competitors);
  } else if (Array.isArray(j.competitors)) {
    competitors = competitors.concat(j.competitors);
  }
}
// fallback: if someone passes the array directly as first item
if (!competitors.length && Array.isArray(items[0]?.json)) {
  competitors = items[0].json;
}

const by_platform = Object.fromEntries(PLATFORMS.map(p => [p, []]));
const all = [];
let linksConsumed = 0;

// ---------- scan competitors ----------
for (const comp of (competitors || [])) {
  // 1) socials object map
  const socials = comp.socials || {};
  for (const [key, value] of Object.entries(socials)) {
    if (Array.isArray(value)) {
      for (const v of value) {
        const plat = detectPlatform(v);
        pushUrl(by_platform[plat], v);
        pushUrl(all, v);
      }
    } else {
      const plat = detectPlatform(value);
      pushUrl(by_platform[plat], value);
      pushUrl(all, value);
    }
  }

  // 2) known extra link arrays if present (future-proof)
  const extraFields = ["links", "pages", "other_links"];
  for (const field of extraFields) {
    if (Array.isArray(comp[field])) {
      for (const v of comp[field]) {
        const plat = detectPlatform(v);
        pushUrl(by_platform[plat], v);
        pushUrl(all, v);
        linksConsumed++;
      }
    }
  }

  // 3) optionally include the root website in "all" & classify it (often ends up as "other")
  if (comp.website) {
    const plat = detectPlatform(comp.website);
    pushUrl(by_platform[plat], comp.website);
    pushUrl(all, comp.website);
  }
}

// ---------- dedupe & sort ----------
for (const p of PLATFORMS) {
  by_platform[p] = uniqCI(by_platform[p]).sort((a, b) => a.localeCompare(b));
}
const allUniq = uniqCI(all).sort((a, b) => a.localeCompare(b));

// ---------- counts ----------
const counts = Object.fromEntries(PLATFORMS.map(p => [p, by_platform[p].length]));

// ---------- debug ----------
const _debug = {
  items_in: Array.isArray(competitors) ? competitors.length : 0,
  records_scanned: Array.isArray(competitors) ? competitors.length : 0,
  used: {
    by_platform: PLATFORMS.length,
    all: allUniq.length,
    links: linksConsumed
  }
};

// ---------- emit ----------
return [
  {
    json: {
      by_platform,
      all: allUniq,
      counts,
      _debug
    }
  }
];

// n8n Function node
// Accepts: single site object, array of sites, {competitors:[]}/{data:[]}, or {output:{competitors:[]}} (your sample)
// Emits: one item per site with { name, website, domain, socials{...} }

function parseHost(u) {
  if (typeof u !== 'string') return '';
  const noProto = u.replace(/^\s*/, '').replace(/^https?:\/\//i, '');
  const noCreds = noProto.replace(/^[^/@]+@/, '');
  const host = noCreds.split('/')[0].split('?')[0].split('#')[0];
  return host.replace(/^www\./i, '').toLowerCase();
}

function domainFromUrl(u) {
  const host = parseHost(u);
  const parts = host.split('.').filter(Boolean);
  if (parts.length >= 2) return parts.slice(-2).join('.');
  return host;
}

function pickName(title, website) {
  const host = parseHost(website);
  if (title && typeof title === 'string') {
    let name = title.split(/[|–—-]/)[0].trim();
    name = name.replace(/\b(home|homepage)\b/i, '').trim();
    if (name) return name;
  }
  const base = (host || '').split('.')[0];
  return base ? base.charAt(0).toUpperCase() + base.slice(1) : '';
}

function extractUrlsFromText(text) {
  const out = [];
  const re = /\bhttps?:\/\/[^\s"'<>)]+/gi;
  let m; while ((m = re.exec(text)) !== null) out.push(m[0]);
  return out;
}

// Robustly gather everything that looks like a URL from common fields
function collectAllUrls(site) {
  const urls = new Set();

  // Primary website
  ['url', 'website', 'homepage'].forEach(k => {
    const v = site?.[k];
    if (typeof v === 'string' && /^https?:\/\//i.test(v)) urls.add(v);
  });

  // Array-of-strings links
  if (Array.isArray(site.links)) {
    site.links.forEach(u => { if (typeof u === 'string') urls.add(u); });
  }

  // Articles/content text
  ['articles', 'body', 'text', 'description'].forEach(k => {
    const v = site?.[k];
    if (Array.isArray(v)) v.forEach(t => { if (typeof t === 'string') extractUrlsFromText(t).forEach(u => urls.add(u)); });
    if (typeof v === 'string') extractUrlsFromText(v).forEach(u => urls.add(u));
  });

  // Meta fields (string values)
  if (site && typeof site.meta === 'object' && site.meta) {
    Object.values(site.meta).forEach(val => {
      if (typeof val === 'string') extractUrlsFromText(val).forEach(u => urls.add(u));
    });
  }

  // Socials object: take any string values as URLs
  if (site && typeof site.socials === 'object' && site.socials) {
    Object.values(site.socials).forEach(u => {
      if (typeof u === 'string' && /^https?:\/\//i.test(u)) urls.add(u);
    });
  }

  return Array.from(urls);
}

// Normalize incoming items to a flat array of "site" objects
function stripFences(s) {
  if (typeof s !== 'string') return s;
  const m = s.match(/```[a-zA-Z]*\n([\s\S]*?)```/);
  return m ? m[1] : s;
}

function normalizeIncoming(items) {
  const sites = [];

  for (const it of (items || [])) {
    let payload = it?.json;

    // unwrap common LLM shapes
    if (typeof payload === 'string') {
      try { payload = JSON.parse(stripFences(payload)); } catch {}
    }
    for (const k of ['body', 'data', 'output']) {
      if (typeof payload?.[k] === 'string') {
        try { payload[k] = JSON.parse(stripFences(payload[k])); } catch {}
      }
    }

    // 1) Raw array of sites
    if (Array.isArray(payload)) {
      payload.forEach(s => { if (s && typeof s === 'object') sites.push(s); });
      continue;
    }

    // 2) {competitors:[...]} or {data:[...]} or {body:[...]}
    if (Array.isArray(payload?.competitors)) {
      payload.competitors.forEach(s => { if (s && typeof s === 'object') sites.push(s); });
      continue;
    }
    if (Array.isArray(payload?.data)) {
      payload.data.forEach(s => { if (s && typeof s === 'object') sites.push(s); });
      continue;
    }
    if (Array.isArray(payload?.body)) {
      payload.body.forEach(s => { if (s && typeof s === 'object') sites.push(s); });
      continue;
    }

    // 3) {output:{competitors:[...]}}  <-- YOUR SAMPLE
    if (payload?.output && Array.isArray(payload.output.competitors)) {
      payload.output.competitors.forEach(s => { if (s && typeof s === 'object') sites.push(s); });
      continue;
    }

    // 4) Single site-like object
    if (payload && typeof payload === 'object') {
      const looksLikeSite = ['url','website','title','links','articles','images','videos','meta','socials']
        .some(k => Object.prototype.hasOwnProperty.call(payload, k));
      if (looksLikeSite) { sites.push(payload); continue; }
    }
  }
  return sites;
}

// Host-based detector
function firstByHost(urls, host, pathRegex) {
  for (const u of urls) {
    const h = domainFromUrl(u);
    if (h === host) {
      if (!pathRegex) return u;
      try {
        const urlObj = new URL(u);
        const path = urlObj.pathname || '';
        if (pathRegex.test(path)) return u;
      } catch {
        if (pathRegex.test(u)) return u; // fallback
      }
    }
  }
  return undefined;
}

const sites = normalizeIncoming(items);

if (!sites.length) {
  const first = items?.[0]?.json ?? null;
  return [{
    json: {
      error: 'No site objects found',
      hint: 'Send a site object, an array of sites, or wrap in {competitors:[...]}, {data:[...]}, or {output:{competitors:[...]}}',
      keys: first && typeof first === 'object' ? Object.keys(first) : typeof first
    }
  }];
}

const out = [];

for (const site of sites) {
  const website = site.website || site.url || site.homepage || '';
  const domain = site.domain || (website ? domainFromUrl(website) : '');
  const urls = collectAllUrls(site);

  // Start from provided socials (if any), then fill in gaps via URL harvesting
  const socials = {};
  if (site && typeof site.socials === 'object' && site.socials) {
    for (const [k, v] of Object.entries(site.socials)) {
      if (typeof v === 'string' && v) socials[k] = v;
    }
  }

  // LinkedIn (company/showcase/school/in/@) or any linkedin.com
  socials.linkedin  = socials.linkedin
    || firstByHost(urls, 'linkedin.com', /(\/(company|showcase|school|in)\/|\/@)/i)
    || firstByHost(urls, 'linkedin.com');

  // X / Twitter
  socials.x         = socials.x
    || firstByHost(urls, 'x.com')
    || firstByHost(urls, 'twitter.com');

  // Instagram
  socials.instagram = socials.instagram
    || firstByHost(urls, 'instagram.com');

  // Facebook
  socials.facebook  = socials.facebook
    || firstByHost(urls, 'facebook.com');

  // TikTok
  socials.tiktok    = socials.tiktok
    || firstByHost(urls, 'tiktok.com');

  // YouTube: support @handle, channel, user, c/, and youtu.be
  socials.youtube   = socials.youtube
    || firstByHost(urls, 'youtube.com', /^\/(@|channel|user|c)\b/i)
    || firstByHost(urls, 'youtu.be');

  // prune empties
  Object.keys(socials).forEach(k => { if (!socials[k]) delete socials[k]; });

  out.push({
    json: {
      name: site.name || pickName(site.title, website),
      website,
      domain,
      socials
    }
  });
}

// Emit one item per site (as per header contract)
return out;

// Code node to build LinkedIn post body with debugging
const allImages = [];
// Get all input items
const inputItems = $input.all();
// Debug: Log what we're receiving
console.log('Number of input items:', inputItems.length);
// Collect all image URNs from input items
for (const item of inputItems) {
  const data = item.json;

  console.log('Processing item:', JSON.stringify(data));

  // Check different possible data structures
  if (data.imageUrns && Array.isArray(data.imageUrns)) {
    console.log('Found imageUrns array with', data.imageUrns.length, 'items');
    data.imageUrns.forEach(urn => {
      allImages.push({ id: urn });
    });
  } else if (data.images && Array.isArray(data.images)) {
    console.log('Found images array with', data.images.length, 'items');
    data.images.forEach(img => {
      if (img.id) {
        allImages.push({ id: img.id });
      } else if (typeof img === 'string') {
        allImages.push({ id: img });
      }
    });
  } else if (data.imageUrn && typeof data.imageUrn === 'string') {
    // Handle single image URN
    console.log('Found single imageUrn');
    allImages.push({ id: data.imageUrn });
  } else {
    console.log('No imageUrns or images array found in item');
  }
}
console.log('Total images collected:', allImages.length);
// Get data from If2 node
const if2Data = $('If2').item.json;
// Build the complete LinkedIn post body
let requestBody;

if (allImages.length === 1) {
  // Use 'media' format for single image
  requestBody = {
    author: `urn:li:organization:${if2Data.linkedin_organization_id}`,
    commentary: if2Data.description,
    visibility: "PUBLIC",
    distribution: {
      feedDistribution: "MAIN_FEED",
      targetEntities: [],
      thirdPartyDistributionChannels: []
    },
    lifecycleState: "PUBLISHED",
    isReshareDisabledByAuthor: false,
    content: {
      media: {
        id: allImages[0].id
      }
    }
  };
} else if (allImages.length >= 2 && allImages.length <= 20) {
  // Use 'multiImage' format for multiple images
  requestBody = {
    author: `urn:li:organization:${if2Data.linkedin_organization_id}`,
    commentary: if2Data.description,
    visibility: "PUBLIC",
    distribution: {
      feedDistribution: "MAIN_FEED",
      targetEntities: [],
      thirdPartyDistributionChannels: []
    },
    lifecycleState: "PUBLISHED",
    isReshareDisabledByAuthor: false,
    content: {
      multiImage: {
        images: allImages
      }
    }
  };
} else {
  throw new Error(`LinkedIn requires 1-20 images. Found ${allImages.length} images. Check your input data structure.`);
}

console.log('Final request body:', JSON.stringify(requestBody, null, 2));
// Return the body ready for HTTP Request node
return [{ json: { requestBody } }];

// Parse the stringified JSON stored in social_id
const data = JSON.parse(items[0].json.social_id);

// Prefer direct key if available
let urn = data["x-restli-id"];

// If not, try to extract from encoded location
if (!urn && data.location) {
  const decoded = decodeURIComponent(data.location);
  const match = decoded.match(/urn:li:[^/]+:\d+/);
  urn = match ? match[0] : null;
}

// Return clean URN
return [{ json: { urn } }];

// Try to locate hashtags field
const input = items[0].json;

// Detect where hashtags might exist
let rawTags =
  input.hashtags ||
  input.data?.hashtags ||
  input.fields?.hashtags ||
  "";

// Normalize and lowercase
const formattedHashtags = rawTags
  .toString()
  .split(/[\s,]+/)
  .filter(Boolean)
  .map(tag => `#${tag.replace(/^#/, "").toLowerCase()}`)
  .join(" ");

// Output for testing
return [{ json: { formattedHashtags, rawTags } }];

